mapper.select:
SELECT u.name AS studentName, l.start_time AS startTime, l.end_time AS endTime, l.day_of_week AS dayOfWeek, s.name AS subjectName FROM payment p INNER JOIN student_enrollment se ON p.enrollment_id = se.enrollment_id INNER JOIN user u ON se.student_id = u.user_id INNER JOIN (SELECT * FROM lecture WHERE end_date > CURDATE()) l ON se.lecture_id = l.lecture_id INNER JOIN subject s ON s.subject_id = l.subject_id WHERE se.lecture_id IN ( SELECT lecture_id FROM teacher_assignment WHERE teacher_id = #{teacherId} )
AND (u.name LIKE CONCAT('%', #{keyword}, '%') OR s.name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY u.name LIMIT #{startRow}, #{rowPerPage}

mapper.update:
UPDATE user
phone = #{phone}, address = #{address}, password = #{password},
WHERE user_id = #{teacherId}

mapper.select:
SELECT * FROM notice WHERE target_role_id = 3
AND ( title LIKE CONCAT('%', #{keyword}, '%') OR content LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY created_at DESC LIMIT #{startRow}, #{rowPerPage}

SELECT notice_id, title, content, admin_id, created_at
FROM notice
WHERE notice_id = #{noticeId}

SELECT a.album_id, a.lecture_id, a.title, a.description, a.created_at, ap.file_path AS filePath FROM album a LEFT JOIN ( SELECT album_id, file_path FROM album_photo WHERE photo_id IN ( SELECT MIN(photo_id) FROM album_photo GROUP BY album_id ) ) ap ON a.album_id = ap.album_id
AND a.title LIKE CONCAT('%', #{keyword}, '%')
ORDER BY a.created_at DESC LIMIT #{startRow}, #{rowPerPage}
